# Container classes that use shapes and points

from shapes import Point, Rectangle

class Box[T]:
    items: list[T]

    def __init__(self):
        self.items = []

    def add(self, item: T):
        self.items.append(item)

    def get_all(self) -> list[T]:
        return self.items

    def count(self) -> int:
        return len(self.items)

    def first(self) -> T:
        if self.count() > 0:
            return self.items[0]
        raise ValueError("Box is empty")


class Grid:
    points: list[Point]

    def __init__(self):
        self.points = []

    def add_point(self, p: Point):
        self.points.append(p)

    def get_bounds(self) -> tuple[min_x: float, min_y: float, max_x: float, max_y: float]:
        if len(self.points) == 0:
            return (min_x=0.0, min_y=0.0, max_x=0.0, max_y=0.0)

        min_x = self.points[0].x
        min_y = self.points[0].y
        max_x = self.points[0].x
        max_y = self.points[0].y

        for p in self.points:
            if p.x < min_x:
                min_x = p.x
            if p.y < min_y:
                min_y = p.y
            if p.x > max_x:
                max_x = p.x
            if p.y > max_y:
                max_y = p.y

        return (min_x=min_x, min_y=min_y, max_x=max_x, max_y=max_y)


class ShapeContainer:
    rectangles: list[Rectangle]

    def __init__(self):
        self.rectangles = []

    def add(self, r: Rectangle):
        self.rectangles.append(r)

    def total_area(self) -> float:
        total: float = 0.0
        for r in self.rectangles:
            total = total + r.area()
        return total

