# Utility functions and classes

from shapes import Point

class Calculator:
    def __init__(self):
        pass

    def hypotenuse(self, a: float, b: float) -> float:
        return (a * a + b * b) ** 0.5

    def midpoint(self, p1: Point, p2: Point) -> Point:
        mid_x = (p1.x + p2.x) / 2.0
        mid_y = (p1.y + p2.y) / 2.0
        return Point(mid_x, mid_y)


class Validator:
    def __init__(self):
        pass

    def is_positive(self, n: float) -> bool:
        return n > 0.0

    def in_range(self, value: float, min_val: float, max_val: float) -> bool:
        return min_val <= value <= max_val


def format_number(n: float, decimals: int) -> str:
    factor: int = 10 ** decimals
    rounded: float = round(n * factor) / factor
    return str(rounded)


def sum_points_x(points: list[Point]) -> float:
    total: float = 0.0
    for p in points:
        total = total + p.x
    return total
